DROP TABLE IF EXISTS _clanwars_windows;
DROP TABLE IF EXISTS _clanwars_player_rows;

CREATE TABLE _clanwars_windows (
  source_report_key TEXT NOT NULL,
  starts_on TEXT NOT NULL,
  ends_on TEXT NOT NULL,
  source_filename TEXT,
  capture_time_local TEXT
);

CREATE TABLE _clanwars_player_rows (
  source_report_key TEXT NOT NULL,
  starts_on TEXT NOT NULL,
  ends_on TEXT NOT NULL,
  canonical_name TEXT NOT NULL,
  display_name TEXT NOT NULL,
  points INTEGER NOT NULL
);



INSERT OR IGNORE INTO competition_window (
  activity_type,
  season_year,
  week_of_year,
  cadence_slot,
  rotation_number,
  starts_at,
  ends_at,
  label
)
SELECT DISTINCT
  'clan_wars',
  CAST(strftime('%Y', cw.ends_on) AS INTEGER) AS season_year,
  CAST(strftime('%W', cw.ends_on) AS INTEGER) + 1 AS week_of_year,
  'biweekly',
  NULL,
  cw.starts_on || 'T00:00:00Z',
  cw.ends_on || 'T00:00:00Z',
  'Clan Wars ' || cw.source_report_key
FROM _clanwars_windows AS cw;

INSERT OR IGNORE INTO player_profile (main_nickname, status)
SELECT DISTINCT
  cpr.canonical_name,
  'active'
FROM _clanwars_player_rows AS cpr
WHERE NOT EXISTS (
  SELECT 1
  FROM player_profile AS pp
  WHERE pp.main_nickname = cpr.canonical_name
);

WITH canonical_profile AS (
  SELECT main_nickname, MIN(id) AS player_profile_id
  FROM player_profile
  GROUP BY main_nickname
)
INSERT OR IGNORE INTO player_alias (
  player_profile_id,
  alias_type,
  alias_value,
  is_primary,
  first_seen_at,
  last_seen_at
)
SELECT
  cp.player_profile_id,
  'game_nickname',
  cpr.canonical_name,
  1,
  MIN(cpr.starts_on || 'T00:00:00Z'),
  MAX(cpr.ends_on || 'T00:00:00Z')
FROM _clanwars_player_rows AS cpr
JOIN canonical_profile AS cp
  ON cp.main_nickname = cpr.canonical_name
GROUP BY cp.player_profile_id, cpr.canonical_name;

  upload_type,
  source_kind,
  scope_type,
  scope_key,
  replace_existing,
  status,
  started_at,
  finished_at,
  notes
)
SELECT DISTINCT
  'admin_bulk_json',
  'historical_data_clan_wars_ocr',
  'competition_window',
  cw.source_report_key,
  1,
  'applied',
  CURRENT_TIMESTAMP,
  CURRENT_TIMESTAMP,
  'Imported from normalized clan wars OCR snapshots'
FROM _clanwars_windows AS cw
WHERE NOT EXISTS (
  SELECT 1
  FROM report_import AS ri
  WHERE ri.upload_type = 'admin_bulk_json'
    AND ri.source_kind = 'historical_data_clan_wars_ocr'
    AND ri.scope_type = 'competition_window'
    AND ri.scope_key = cw.source_report_key
);

INSERT OR IGNORE INTO clan_wars_report (
  competition_window_id,
  report_import_id,
  source_system,
  is_partial
)
SELECT
  cw_db.id,
  (
    SELECT ri.id
    FROM report_import AS ri
    WHERE ri.scope_type = 'competition_window'
      AND ri.scope_key = cw.source_report_key
    ORDER BY ri.id DESC
    LIMIT 1
  ) AS report_import_id,
  'historical-clan-wars-ocr',
  1
FROM _clanwars_windows AS cw
JOIN competition_window AS cw_db
  ON cw_db.activity_type = 'clan_wars'
  AND cw_db.cadence_slot = 'biweekly'
  AND cw_db.starts_at = cw.starts_on || 'T00:00:00Z'
  AND cw_db.ends_at = cw.ends_on || 'T00:00:00Z';

  clan_wars_report_id,
  competition_window_id,
  player_profile_id,
  display_name_at_import,
  points
)
SELECT
  cwr.id,
  cw_db.id,
  COALESCE(pa.player_profile_id, cp.player_profile_id) AS player_profile_id,
  cpr.display_name,
  cpr.points
FROM _clanwars_player_rows AS cpr
LEFT JOIN player_alias AS pa
  ON pa.alias_type = 'game_nickname'
  AND pa.alias_value = cpr.canonical_name
LEFT JOIN (
  SELECT main_nickname, MIN(id) AS player_profile_id
  FROM player_profile
  GROUP BY main_nickname
) AS cp
  ON cp.main_nickname = cpr.canonical_name
JOIN competition_window AS cw_db
  ON cw_db.activity_type = 'clan_wars'
  AND cw_db.cadence_slot = 'biweekly'
  AND cw_db.starts_at = cpr.starts_on || 'T00:00:00Z'
  AND cw_db.ends_at = cpr.ends_on || 'T00:00:00Z'
JOIN clan_wars_report AS cwr
  ON cwr.competition_window_id = cw_db.id
WHERE COALESCE(pa.player_profile_id, cp.player_profile_id) IS NOT NULL
ON CONFLICT (clan_wars_report_id, player_profile_id) DO UPDATE SET
  points = excluded.points,
  display_name_at_import = excluded.display_name_at_import;

